import React, { Fragment, useState } from 'react'
import { Card, CardBody, CardHeader, Col, Container, Row } from 'reactstrap';
import Breadcrumb from '../components/common/Breadcrumb';
import NodeDashboard from '../components/common/NodeDashboard';
import { UserState } from '../context/User';

const Dashboard = () => {
  const { user } = UserState();
  const { nodes, setNodes } = useState();
  const { context, setContext } = useState();
  const {loading,setLoading} = useState(true);
  const fetchNode = async (para) => {
    let dataRaw = await fetch("/Data/Read", {
      method: "POST",
      headers: {
        "Content-type": "application/json;charset=utf-8",
        method: "POST",
      },
      body: JSON.stringify({
        accountId: para,
      })
    });
    let data = await dataRaw.json();
    console.log(data);
  };
  if (user) {
    fetchNode(user._id).then((result) => {
      if (result) {
        console.log(result);
        setContext(result);
      }
    });
  }
  return (
    <Fragment>
      {
        user && <Breadcrumb title="Dashboard" parent="Dashboard" />
      }

      <Container fluid={true}>
        <Row>
          <Col sm="12">
            <Card>
              <CardHeader>
                <h5>Products Category</h5>
              </CardHeader>
              <CardBody>
                <NodeDashboard title={`Flowin`} unit={`m3/h`} key={`1`} />
              </CardBody>
            </Card>
          </Col>

        </Row>
      </Container>



    </Fragment>
  )
}

export default Dashboard;
